SELECT ?clubLabel (COUNT(?event) AS ?wins) WHERE {
  VALUES ?club { wd:Q283049 wd:Q284152 wd:Q285664 }
  wd:Q5070151 wdt:P527 ?event.
  ?event wdt:P1346 ?club.
  ?club rdfs:label ?clubLabel.
  FILTER(lang(?clubLabel) = 'en')
}
GROUP BY ?club ?clubLabel
ORDER BY DESC(?wins)

